### Java Code:

```java
import java.awt.image.BufferedImage;
import java.awt.image.Kernel;
import java.awt.image.ConvolveOp;
import java.awt.image.EllipseKernel;
import java.awt.image.FilteredImageSource;
import java.io.*;
import javax.imageio.ImageIO;
import java.net.URL;

public class ImageFilterDownloader {

    public static void main(String[] args) {
        String imageUrl = "https://example.com/sample-image.jpg"; // Replace with your URL
        String outputPath = "filtered_image.jpg";

        try {
            BufferedImage originalImage = downloadAndLoadImage(imageUrl);
            BufferedImage filteredImage = applyGrayscaleFilter(originalImage);
            saveImage(filteredImage, outputPath);
            System.out.println("Image downloaded and filtered successfully.");
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    private static BufferedImage downloadAndLoadImage(String imageUrl) throws IOException {
        URL url = new URL(imageUrl);
        BufferedImage image = ImageIO.read(url.openStream());
        return image;
    }

    private static BufferedImage applyGrayscaleFilter(BufferedImage image) {
        BufferedImage filtered = new BufferedImage(image.getWidth(), image.getHeight(), image.getType());

        // Create a grayscale kernel
        Kernel kernel = new EllipseKernel(1, 1, 1, 1, 0.5f); // Simple grayscale kernel

        ConvolveOp convolveOp = new ConvolveOp(kernel, ConvolveOp.EDGE_NO_OP, new Kernel(3, 3, 0.5f));
        FilteredImageSource source = new FilteredImageSource(image.getSource(), convolveOp);
        Graphics2D g2d = filtered.createGraphics();
        g2d.drawImage(source, 0, 0, filtered.getWidth(), filtered.getHeight(), null);
        g2d.dispose();

        return filtered;
    }

    private static void saveImage(BufferedImage image, String outputPath) throws IOException {
        ImageIO.write(image, "jpg", new File(outputPath));
    }
}
```

---

### Explanation:

- **`downloadAndLoadImage`**: Downloads the image from the URL and returns it as a `BufferedImage`.
- **`applyGrayscaleFilter`**: Applies a grayscale filter using a `ConvolveOp` with a simple kernel.
- **`saveImage`**: Saves the filtered image to the specified file path.

---

### Notes:
- You can modify the `Kernel` to apply different filters (e.g., blur, contrast, etc.).
- Ensure the URL is valid and accessible.
- This example uses JPEG format; you can change the format as needed.

